@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

package "Modulo-matrícula/Informática" {
  class "Matrícula" {
    <<Class>>
    -id: Int
    -cliente: Client
    -tempo: Int
    -quadra: Turma
    +registraMatrícula(): Int
  }

  class "Aluno" {
    <<Class>>
    -id: Int
    -nome: String
    -locação: List<Matrícula>
  }

  interface "ControleNúmeroMatrícula" {
    <<Interface>>
    #quantidadeDeMatrícula: Int
    +registraMatrícula(): Int
  }

  class "Turma" {
    <<Class>>
    -numero: Int
    -aluguel: Matrícula
    -ginasio: Curso
    +getcontroleNúmeroMatrícula()
  }

  class "Curso" {
    <<Class>>
    -nome: String
    -profe
    -quadra: List<Turma>
  }
}

"Matrícula" ..|> "ControleNúmeroMatrícula" : realização
"Turma" --> "ControleNúmeroMatrícula" : dependência
"Matrícula" *-- "Turma" : composição
"Turma" *-- "Curso" : composição
"Aluno" --> "Matrícula" : composição

@enduml
